Name={clsx('recharts-curve', className)}\n      d={realPath === null ? undefined : realPath}\n      ref={pathRef}\n    />\n  );\n};\n","/**\n * @fileOverview Cross\n */\nimport * as React from 'react';\nimport { SVGProps } from 'react';\nimport { clsx } from 'clsx';\nimport { isNumber } from '../util/DataUtils';\nimport { svgPropertiesAndEvents } from '../util/svgPropertiesAndEvents';\n\ninterface CrossProps {\n  /**\n   * The x-coordinate of the vertical line of the cross in pixels.\n   */\n  x?: number;\n  /**\n   * The y-coordinate of the horizontal line of the cross in pixels.\n   */\n  y?: number;\n  /**\n   * Width of the cross in pixels.\n   */\n  width?: number;\n  /**\n   * Height of the cross in pixels.\n   */\n  height?: number;\n  /**\n   * The y-coordinate of the top left point in the boundary box of the cross.\n   */\n  top?: number;\n  /**\n   * The x-coordinate of the top left point in the boundary box of the cross.\n   */\n  left?: number;\n  className?: number;\n}\n\nexport type Props = SVGProps<SVGPathElement> & CrossProps;\n\nconst getPath = (x: number, y: number, width: number, height: number, top: number, left: number) => {\n  return `M${x},${top}v${height}M${left},${y}h${width}`;\n};\n\nexport const Cross: React.FC<Props> = ({\n  x = 0,\n  y = 0,\n  top = 0,\n  left = 0,\n  width = 0,\n  height = 0,\n  className,\n  ...rest\n}) => {\n  const props = { x, y, top, left, width, height, ...rest };\n\n  if (!isNumber(x) || !isNumber(y) || !isNumber(width) || !isNumber(height) || !isNumber(top) || !isNumber(left)) {\n    return null;\n  }\n\n  return (\n    <path\n      {...svgPropertiesAndEvents(props)}\n      className={clsx('recharts-cross', className)}\n      d={getPath(x, y, width, height, top, left)}\n    />\n  );\n};\n","export const ACCURACY = 1e-4;\n\nconst cubicBezierFactor = (c1: number, c2: number) => [0, 3 * c1, 3 * c2 - 6 * c1, 3 * c1 - 3 * c2 + 1];\n\nconst evaluatePolynomial = (params: ReadonlyArray<number>, animationElapsedTime: number) =>\n  params.map((param, i) => param * animationElapsedTime ** i).reduce((pre, curr) => pre + curr);\n\nconst cubicBezier = (c1: number, c2: number) => (animationElapsedTime: number) => {\n  const params = cubicBezierFactor(c1, c2);\n\n  return evaluatePolynomial(params, animationElapsedTime);\n};\n\nconst derivativeCubicBezier = (c1: number, c2: number) => (animationElapsedTime: number) => {\n  const params = cubicBezierFactor(c1, c2);\n  const newParams = [...params.map((param, i) => param * i).slice(1), 0];\n\n  return evaluatePolynomial(newParams, animationElapsedTime);\n};\n\ntype CubicBezierTemplate = `cubic-bezier(${number},${number},${number},${number})`;\n\nexport type NamedBezier = 'linear' | 'ease' | 'ease-in' | 'ease-out' | 'ease-in-out' | CubicBezierTemplate;\n\ntype BezierInput = [NamedBezier] | [number, number, number, number];\n\nexport type BezierEasingFunction = {\n  isStepper: false;\n  (animationElapsedTime: number): number;\n};\n\nconst parseCubicBezier = (easing: string): [number, number, number, number] | null => {\n  const easingParts = easing.split('(');\n  if (easingParts.length !== 2 || easingParts[0] !== 'cubic-bezier') {\n    return null;\n  }\n  const numbers = easingParts[1]?.split(')')[0]?.split(',');\n  if (numbers == null || numbers.length !== 4) {\n    return null;\n  }\n  const coords = numbers.map((x: string) => parseFloat(x));\n  return [coords[0]!, coords[1]!, coords[2]!, coords[3]!];\n};\n\nconst getBezierCoordinates = (...args: BezierInput): [number, number, number, number] => {\n  if (args.length === 1) {\n    switch (args[0]) {\n      case 'linear':\n        return [0.0, 0.0, 1.0, 1.0];\n      case 'ease':\n        return [0.25, 0.1, 0.25, 1.0];\n      case 'ease-in':\n        return [0.42, 0.0, 1.0, 1.0];\n      case 'ease-out':\n        return [0.42, 0.0, 0.58, 1.0];\n      case 'ease-in-out':\n        return [0.0, 0.0, 0.58, 1.0];\n      default: {\n        const easing = parseCubicBezier(args[0]);\n        if (easing) {\n          return easing;\n        }\n      }\n    }\n  }\n\n  if (args.length === 4) {\n    return args;\n  }\n\n  // Fallback for invalid inputs. The previous implementation was buggy and would lead to NaN.\n  // Returning linear easing is a safe default.\n  return [0.0, 0.0, 1.0, 1.0];\n};\n\nconst createBezierEasing = (x1: number, y1: number, x2: number, y2: number): BezierEasingFunction => {\n  const curveX = cubicBezier(x1, x2);\n  const curveY = cubicBezier(y1, y2);\n  const derCurveX = derivativeCubicBezier(x1, x2);\n  const rangeValue = (value: number): number => {\n    if (value > 1) {\n      return 1;\n    }\n    if (value < 0) {\n      return 0;\n    }\n\n    return value;\n  };\n\n  const bezier = (_animationElapsedTime: number) => {\n    const animationElapsedTime = _animationElapsedTime > 1 ? 1 : _animationElapsedTime;\n    let x = animationElapsedTime;\n\n    for (let i = 0; i < 8; ++i) {\n      const evalT = curveX(x) - animationElapsedTime;\n      const derVal = derCurveX(x);\n\n      if (Math.abs(evalT - animationElapsedTime) < ACCURACY || derVal < ACCURACY) {\n        return curveY(x);\n      }\n\n      x = rangeValue(x - evalT / derVal);\n    }\n\n    return curveY(x);\n  };\n\n  bezier.isStepper = false as const;\n\n  return bezier;\n};\n\n// calculate cubic-bezier using Newton's method\nexport const configBezier = (...args: BezierInput): BezierEasingFunction => {\n  return createBezierEasing(...getBezierCoordinates(...args));\n};\n\ntype SpringInput = {\n  /**\n   * The stiffness coefficient of the spring.\n   * Higher values create a more forceful, faster pull towards the target.\n   */\n  stiff?: number;\n  /**\n   * The damping coefficient (friction/resistance).\n   * Higher values reduce bounciness and stop oscillation sooner. Lower values create more bounce.\n   */\n  damping?: number;\n  /**\n   * The physics simulation time step in milliseconds.\n   * Determines the granularity of the baked frames. 16.67ms roughly equals a 60fps frame delta.\n   */\n  dt?: number;\n};\n\n/**\n * Creates a performance-optimized, progress-based spring easing function.\n * It pre-calculates (\"bakes\") spring physics frames upfront based on a fixed duration,\n * then returns a pure, lightweight function mapping progress (0 to 1) to the animated position.\n * This approach is ideal for low-power devices because it removes heavy physics math from the frame loop.\n */\nexport const createSpringEasing = (config: SpringInput = {}): EasingFunction => {\n  const { stiff = 100, damping = 8, dt = 16.67 } = config;\n  const destX = 1;\n\n  const positions: number[] = [0];\n  let currX = 0;\n  let currV = 0;\n\n  // Safety valve to prevent accidental infinite loops if physics config is extreme\n  const maxIterations = 10000;\n  let iterations = 0;\n\n  // 1. Run the simulation until the spring completely stops moving\n  while (iterations < maxIterations) {\n    const FSpring = -(currX - destX) * stiff;\n    const FDamping = currV * damping;\n\n    currV += ((FSpring - FDamping) * dt) / 1000;\n    currX += (currV * dt) / 1000;\n\n    positions.push(currX);\n\n    // Stop only when position is essentially at 1.0 AND bounce velocity has died down\n    if (Math.abs(currX - destX) < ACCURACY && Math.abs(currV) < ACCURACY) {\n      break;\n    }\n    iterations++;\n  }\n\n  // Force the absolute final element to be exactly 1.0 for a perfect finish\n  positions[positions.length - 1] = destX;\n  const maxIndex = positions.length - 1;\n\n  // 2. The ultra-smooth runtime function mapping your 0..1 progress\n  return (t: number): number => {\n    if (t <= 0) return 0;\n    if (t >= 1) return destX;\n\n    // Scale t (0..1) proportionally across our entire pre-calculated array\n    const exactFrame = t * maxIndex;\n    const index = Math.floor(exactFrame);\n    const fraction = exactFrame - index;\n\n    // Blend between the two closest frames\n    return (positions[index] ?? 0) + ((positions[index + 1] ?? 0) - (positions[index] ?? 0)) * fraction;\n  };\n};\n\nexport type EasingFunction = (t: number) => number;\n\n/**\n * @inline\n */\nexport type EasingInput = NamedBezier | 'spring' | EasingFunction;\n\nexport const createEasingFunction = (easing: EasingInput): EasingFunction | null => {\n  if (typeof easing === 'string') {\n    switch (easing) {\n      case 'ease':\n      case 'ease-in-out':\n      case 'ease-out':\n      case 'ease-in':\n      case 'linear':\n        return configBezier(easing);\n      case 'spring':\n        return createSpringEasing();\n      default:\n        if (easing.split('(')[0] === 'cubic-bezier') {\n          return configBezier(easing);\n        }\n    }\n  }\n\n  if (typeof easing === 'function') {\n    return easing;\n  }\n\n  return null;\n};\n","import { AnimationController, OnAnimationStateUpdate } from './AnimationController';\nimport { AnimationHandle } from './AnimationHandle';\nimport { CancelableTimeout, TimeoutController } from './timeoutController';\n\n/**\n * JavaScript animations require trigger and repaint as soon as possible,\n * so this class uses the timeoutController to trigger updates as quickly as the controller allows.\n *\n * JavaScript animation progress is represented as a stream of values. The exact type depends on the animationHandle type.\n * Each individual consumer is then responsible for mapping those values onto a React component.\n */\nexport const animationControllerImpl: AnimationController = (\n  timeoutController: TimeoutController,\n  animationHandle: AnimationHandle,\n  listener: OnAnimationStateUpdate,\n): CancelableTimeout => {\n  let cancellable: CancelableTimeout | undefined;\n  const nextUpdate = (now: number) => {\n    const timeRemaining = animationHandle.tick(now);\n    if (animationHandle.getState() === 'active') {\n      listener(animationHandle.getInterpolated());\n      if (animationHandle.getProgress() === 1) {\n        animationHandle.complete();\n        cancellable = undefined;\n        return;\n      }\n      cancellable = timeoutController.setTimeout(nextUpdate, timeRemaining);\n      return;\n    }\n    cancellable = timeoutController.setTimeout(nextUpdate, timeRemaining);\n  };\n\n  cancellable = timeoutController.setTimeout(nextUpdate, 0);\n\n  return () => cancellable?.();\n};\n","import { createContext, useContext, useMemo } from 'react';\nimport { AnimationController } from './AnimationController';\nimport { animationControllerImpl } from './AnimationControllerImpl';\n\nconst AnimationControllerContext = createContext<AnimationController>(animationControllerImpl);\n\n/**\n * Allows overriding the default AnimationController that Recharts uses internally to drive animations.\n * The default one uses requestAnimationFrame-based TimeoutController, and ticks through the animations\n * as time moves forward.\n *\n * Why would you want to use this? Several reasons:\n * - Unit tests are an excellent use (Recharts itself has ton of tests with mock TimeoutController)\n * - If you want to animate charts back and forth (Recharts only animates forward)\n * - If you want to replace requestAnimationFrame with something else\n *   - Perhaps a manual animation controls (https://recharts.github.io does this)\n *   - If you want to maybe animate charts based on mouse movement, or page scroll position, instead of time\n *\n * If you don't use this provider then all charts use the default requestAnimationFrame and default animation logic.\n *\n * If you use this component then all charts inside use your custom animationController.\n *\n * @see {@link https://recharts.github.io/en-US/guide/animations/ Animation guide}\n *\n * @since 3.9\n */\nexport const AnimationControllerProvider = AnimationControllerContext.Provider;\n\nexport function useAnimationController(\n  animationControllerFromProps: AnimationController | undefined,\n): AnimationController {\n  const animationControllerFromContext = useContext(AnimationControllerContext);\n  return useMemo(\n    () => animationControllerFromProps ?? animationControllerFromContext,\n    [animationControllerFromProps, animationControllerFromContext],\n  );\n}\n","// eslint-disable-next-line max-classes-per-file\nimport { interpolate } from '../util/DataUtils';\nimport { EasingFunction, NamedBezier } from './easing';\n\nconst INIT = 'init' as const;\nconst PENDING = 'pending' as const;\nconst ACTIVE = 'active' as const;\nconst COMPLETED = 'completed' as const;\n\nexport type AnimationState = typeof INIT | typeof PENDING | typeof ACTIVE | typeof COMPLETED;\n\ntype AnimationStateCallback = () => void;\n\nfunction duration(time: number): number {\n  return Math.max(0, time);\n}\n\nabstract class RechartsAnimation<T, E> {\n  /**\n   * Returns the absolute time after the animationBegin delay has been completed,\n   * and when the animationDuration started ticking.\n   */\n  public getAnimationStartedTime(): number | undefined {\n    return this.animationStartedTime;\n  }\n\n  /**\n   * Returns the absolute time of when the animation began - now it will wait for {animationBegin} ms before the transition starts\n   */\n  public getBeginStartedTime(): number | undefined {\n    return this.beginStartedTime;\n  }\n\n  private readonly onAnimationEnd: undefined | AnimationStateCallback;\n\n  private progress: number;\n\n  private animationStartedTime: number | undefined;\n\n  private beginStartedTime: number | undefined;\n\n  protected readonly animationDuration: number;\n\n  private readonly animationBegin: number;\n\n  private readonly from: T;\n\n  private readonly to: T;\n\n  protected readonly easing: E;\n\n  private readonly animationId: string;\n\n  constructor(param: {\n    animationId: string;\n    onAnimationStart: undefined | AnimationStateCallback;\n    onAnimationEnd: undefined | AnimationStateCallback;\n    animationDuration: number;\n    animationBegin: number;\n    from: T;\n    to: T;\n    easing: E;\n  }) {\n    this.animationId = param.animationId;\n    this.onAnimationEnd = param.onAnimationEnd;\n    this.animationDuration = duration(param.animationDuration);\n    this.animationBegin = duration(param.animationBegin);\n    this.progress = 0;\n    this.from = param.from;\n    this.to = param.to;\n    this.easing = param.easing;\n    // Mimic what the previous animationManager was doing - call onAnimationStart immediately and synchronously\n    param.onAnimationStart?.();\n  }\n\n  private state: AnimationState = INIT;\n\n  /**\n   * Returns the state machine current state\n   * - `init`:       animation had just been created. It immediately calls `onAnimationStart`\n   * - `pending`:    animation is now paused for `animationBegin` milliseconds until the transition begins\n   * - `active`:     animation is transitioning items on screen\n   * - `completed`:  animation has completed its transition and executed `onAnimationEnd`.\n   *                 This state is final and the animation is no longer allowed to transition to other states.\n   */\n  public getState() {\n    return this.state;\n  }\n\n  /**\n   * Returns the easing input or function\n   */\n  public getEasing(): E {\n    return this.easing;\n  }\n\n  /**\n   * Returns the configuration - the duration of the transition.\n   * Does not change in time, does not change when state changes, this is a static value.\n   */\n  public getAnimationDuration(): number {\n    return this.animationDuration;\n  }\n\n  /**\n   * Sets the current time of the animation. The animation sets its internal state and progress accordingly.\n   * This is current, absolute time; not additive!\n   * This allows you to essentially \"travel back in time\" based on the value you pass in here.\n   *\n   * Returns the (relative) time remaining until the current activity is over.\n   * Meaning: if the state is in a middle of a delay, returns the time left until the delay is finished.\n   * If the state is in the middle of a transition, returns time left until that transition is complete.\n   * This is useful because it's the same number you can take and put into setTimeout(fn, X)\n   * as that's how much time we need to wait until the next state transition happens.\n   */\n  public tick(now: number): number {\n    if (this.getState() === INIT) {\n      this.state = PENDING;\n      this.beginStartedTime = now;\n      return this.animationBegin;\n    }\n\n    if (this.getState() === PENDING) {\n      if (this.beginStartedTime == null) {\n        throw new Error();\n      }\n      const timeElapsed = now - this.beginStartedTime;\n      if (timeElapsed >= this.animationBegin) {\n        this.state = ACTIVE;\n        this.animationStartedTime = now;\n        // The state flipped just now so the elapsed time is zero\n        return this.nextAnimationUpdate(0);\n      }\n      return duration(this.animationBegin - timeElapsed);\n    }\n\n    if (this.getState() === ACTIVE) {\n      if (this.animationStartedTime == null) {\n        throw new Error();\n      }\n      const timeElapsed = now - this.animationStartedTime;\n      this.setProgress(timeElapsed / this.animationDuration);\n      return this.nextAnimationUpdate(timeElapsed);\n    }\n\n    // state === COMPLETED, nothing interesting is going to happen\n    return 0;\n  }\n\n  private setProgress(newProgress: number) {\n    this.progress = Math.min(1, Math.max(0, newProgress));\n  }\n\n  /**\n   * Returns an abstract \"progress\" which is number between 0 and 1 which shows the distance of transition.\n   * This progress depends on the animation state:\n   * - `init`: 0\n   * - `pending`: 0\n   * - `active`: transitioning between [0, 1] based on the time elapsed\n   * - `completed`: 1\n   *\n   * The progress is hard-capped to be between 0 and 1 (inclusive) to avoid overshooting caused by coarse timers.\n   * For this reason, the easing function must be applied _after_ this animation state,\n   * so that one has a chance to construct dynamic \"overshoot\" animations.\n   *\n   * The progress is linear with time.\n   * If you wish for easing, use `getInterpolated()` instead.\n   */\n  public getProgress(): number {\n    return this.progress;\n  }\n\n  /**\n   * Completes the animation. Completed animation:\n   * - cannot be manipulated anymore\n   * - its progress is set to 1\n   * - tick function doesn't do anything\n   * - getState() always returns 'completed'\n   */\n  public complete() {\n    this.progress = 1;\n    if (this.state === 'active') {\n      // Do not call callbacks if the animation was interrupted before it even started!\n      this.onAnimationEnd?.();\n    }\n    this.state = COMPLETED;\n  }\n\n  /**\n   * Returns the starting value of the animation.\n   * Does not include progress, easing, interpolation, none of that - just the static starting value\n   */\n  public getFrom() {\n    return this.from;\n  }\n\n  /**\n   * Returns the end value of the animation.\n   * Does not include progress, easing, interpolation, none of that - just the static end value\n   */\n  public getTo() {\n    return this.to;\n  }\n\n  /**\n   * Unique identifier of an animation\n   */\n  public getAnimationId(): string {\n    return this.animationId;\n  }\n\n  /**\n   * Returns the configuration - the duration of delay in between animation initialization, and transition.\n   * Does not change in time, does not change when state changes, this is a static value.\n   */\n  getAnimationBegin(): number {\n    return this.animationBegin;\n  }\n\n  /**\n   * Returns value of the transition at the current time.\n   * The exact details differ based on the animation type\n   */\n  public abstract getInterpolated(): T;\n\n  /**\n   * Returns the duration of time of when the controller should ask for the next update\n   */\n  protected abstract nextAnimationUpdate(timeElapsed: number): number;\n}\n\n/**\n * Animation handle representing a Javascript-based animation.\n * This animation requires one render cycle for each frame, and it calls setTimeout as quickly as possible\n *\n * @since 3.9\n */\nexport class JavascriptAnimation extends RechartsAnimation<number, EasingFunction> {\n  // eslint-disable-next-line class-methods-use-this\n  protected nextAnimationUpdate(): number {\n    /*\n     * JavaScript-based animations have to update as soon as possible,\n     * so we return 0 here to indicate that the next update should be scheduled immediately\n     * and it should trigger render on every occasion.\n     */\n    return 0;\n  }\n\n  /**\n   * Returns value of the animation after its easing function had been applied.\n   * This value, unlike getProgress(), can escape the [0..1] range\n   * because this is entirely within the easing function control. Spring typically does this.\n   */\n  public getInterpolated(): number {\n    return this.easing(interpolate(this.getFrom(), this.getTo(), this.getProgress()));\n  }\n}\n\n/**\n * Animation handle representing a CSS transition.\n * This animation requires only one render, and the actual transition is then handled by the browser.\n *\n * @since 3.9\n */\nexport class CSSTransitionAnimation extends RechartsAnimation<string, NamedBezier> {\n  protected nextAnimationUpdate(timeElapsed: number): number {\n    /**\n     * CSS transitions do not need DOM updates past the initial render\n     * so here we just instruct the controller to wait until the animation duration is over.\n     */\n    return duration(this.animationDuration - timeElapsed);\n  }\n\n  /**\n   * Returns the final value of the animation (the `to`).\n   *\n   * CSS transitions leave both interpolation and easing to the browser,\n   * so all we need to do here is return the final state\n   * and let browser handle the rest.\n   */\n  public getInterpolated(): string {\n    return this.getTo();\n  }\n}\n\n/**\n * Recharts animation state machine.\n *\n * Possible transitions are:\n * - `init`: starting state - `onAnimationStart` executes\n * - `init` to `pending` - `animationBegin` duration begins\n * - `pending` to `active` - `animationDuration` duration begins, timer ticks decide the progress\n * - `active` to `completed` - `onAnimationEnd` executes\n *\n * The state always moves in this direction, cannot move backwards.\n *\n * The animation queue is static and consists of four elements:\n * - `onAnimationStart`: function that is called when the animation is created\n * - `animationBegin`: delay between `onAnimationStart` and the transition\n * - the transition itself, takes `animationDuration` ms to finish\n * - `onAnimationEnd`: function that is called when the animation is moving from `active` to `completed`\n *\n * @see {@link https://recharts.github.io/en-US/guide/animations/ Animation guide}\n *\n * @since 3.9\n */\nexport type AnimationHandle = JavascriptAnimation | CSSTransitionAnimation;\n","/**\n * Callback type for the timeout function.\n * Receives current time as an argument.\n */\nexport type CallbackType = (now: number) => void;\n\n/**\n * A function that, when called, cancels the timeout.\n *\n * @since 3.9\n */\nexport type CancelableTimeout = () => void;\n\n/**\n * TimeoutController is responsible for controlling the movement of time.\n * Think of it as a clock.\n *\n * Recharts default implementation uses requestAnimationFrame which works great in a browser.\n * You may choose to override this which is especially useful if you want to control animations.\n *\n * Why would you want to do this?\n * - unit tests\n * - animations based on something other than time: UI controls, page scroll, mouse movement ...\n *\n * @see {@link https://recharts.github.io/en-US/guide/animations/ Animation guide}\n *\n * @since 3.9\n */\nexport interface TimeoutController {\n  /**\n   * Sets a timeout that executes a callback after a specified delay.\n   * Allows setting multiple timeouts and provides a way to cancel them independently.\n   *\n   * Note that this one function has two different time systems!\n   * The input (delay - parameter of setTimeout)\n   * - is relative\n   * - it means \"wait for this long\"\n   * -\n   *\n   * The output (now - parameter of the callback) is absolute; it means \"this is the time now\"\n   *\n   * @param callback - The function to execute after the delay. Receives the current absolute time in milliseconds as an argument.\n   * @param delay (optional) - The duration of time in milliseconds to wait before executing the callback. Defaults to 0.\n   */\n  setTimeout(callback: CallbackType, delay?: number): CancelableTimeout;\n}\n\nexport class RequestAnimationFrameTimeoutController implements TimeoutController {\n  setTimeout(callback: CallbackType, delay: number = 0): CancelableTimeout {\n    const startTime = performance.now();\n\n    let requestId: number | null = null;\n\n    const executeCallback = (now: number): void => {\n      if (now - startTime >= delay) {\n        callback(now);\n      } else {\n        requestId = requestAnimationFrame(executeCallback);\n      }\n    };\n\n    requestId = requestAnimationFrame(executeCallback);\n\n    return () => {\n      if (requestId != null) {\n        cancelAnimationFrame(requestId);\n      }\n    };\n  }\n}\n","import * as React from 'react';\nimport { useEffect, useState } from 'react';\nimport { noop } from '../util/DataUtils';\nimport { resolveDefaultProps } from '../util/resolveDefaultProps';\nimport { createEasingFunction, EasingInput } from './easing';\nimport { useAnimationController } from './useAnimationController';\nimport { Global } from '../util/Global';\nimport { usePrefersReducedMotion } from '../util/usePrefersReducedMotion';\nimport { JavascriptAnimation } from './AnimationHandle';\nimport { RequestAnimationFrameTimeoutController } from './timeoutController';\nimport { AnimationController } from './AnimationController';\n\ntype JavascriptAnimateProps = {\n  animationId: string;\n  animationController?: AnimationController;\n  duration?: number;\n  begin?: number;\n  easing?: EasingInput;\n  isActive?: boolean | 'auto';\n  canBegin?: boolean;\n  onAnimationStart?: () => void;\n  onAnimationEnd?: () => void;\n  children: (animationElapsedTime: number) => React.ReactNode;\n};\n\nconst defaultJavascriptAnimateProps = {\n  begin: 0,\n  duration: 1000,\n  easing: 'ease',\n  isActive: true,\n  canBegin: true,\n  onAnimationEnd: () => {},\n  onAnimationStart: () => {},\n} as const satisfies Partial<JavascriptAnimateProps>;\n\nconst from = 0;\nconst to = 1;\n\nexport function JavascriptAnimate(outsideProps: JavascriptAnimateProps) {\n  const props = resolveDefaultProps(outsideProps, defaultJavascriptAnimateProps);\n  const {\n    animationId,\n    isActive: isActiveProp,\n    canBegin,\n    duration,\n    easing,\n    begin,\n    onAnimationEnd,\n    onAnimationStart,\n    children,\n  } = props;\n\n  const prefersReducedMotion = usePrefersReducedMotion();\n\n  const isActive = isActiveProp === 'auto' ? !Global.isSsr && !prefersReducedMotion : isActiveProp;\n\n  const animationController = useAnimationController(props.animationController);\n  const [style, setStyle] = useState<number | string>(isActive ? from : to);\n\n  useEffect(() => {\n    if (!isActive) {\n      setStyle(to);\n    }\n  }, [isActive]);\n\n  useEffect(() => {\n    const easingFunction = createEasingFunction(easing);\n\n    if (!isActive || !canBegin || easingFunction == null) {\n      return noop;\n    }\n\n    const timeoutController = new RequestAnimationFrameTimeoutController();\n\n    const animation = new JavascriptAnimation({\n      animationId,\n      easing: easingFunction,\n      animationDuration: duration,\n      animationBegin: begin,\n      onAnimationStart,\n      onAnimationEnd,\n      from,\n      to,\n    });\n\n    return animationController(timeoutController, animation, setStyle);\n  }, [animationController, animationId, isActive, canBegin, duration, easing, begin, onAnimationStart, onAnimationEnd]);\n\n  return children(Number(style));\n}\n","import { useRef } from 'react';\nimport { uniqueId } from './DataUtils';\n\n/**\n * This hook returns a unique animation id for the object