  const from = `0px ${totalLength === -1 ? 1 : totalLength}px`;\n  const to = `${totalLength}px ${totalLength}px`;\n  const transition = getTransitionVal(\n    ['strokeDasharray'],\n    animationDuration,\n    typeof animationEasing === 'string' ? animationEasing : defaultRectangleProps.animationEasing,\n  );\n\n  return (\n    <JavascriptAnimate\n      animationId={animationId}\n      key={animationId}\n      canBegin={totalLength > 0}\n      duration={animationDuration}\n      easing={animationEasing}\n      isActive={isUpdateAnimationActive}\n      begin={animationBegin}\n    >\n      {(animationElapsedTime: number) => {\n        const currWidth = interpolate(prevWidth, width, animationElapsedTime);\n        const currHeight = interpolate(prevHeight, height, animationElapsedTime);\n        const currX = interpolate(prevX, x, animationElapsedTime);\n        const currY = interpolate(prevY, y, animationElapsedTime);\n        if (pathRef.current) {\n          prevWidthRef.current = currWidth;\n          prevHeightRef.current = currHeight;\n          prevXRef.current = currX;\n          prevYRef.current = currY;\n        }\n        let animationStyle: { transition: string; strokeDasharray: string } | { strokeDasharray: string };\n        if (!isAnimationActive) {\n          animationStyle = { strokeDasharray: to };\n        } else if (animationElapsedTime > 0) {\n          animationStyle = { transition, strokeDasharray: to };\n        } else {\n          animationStyle = { strokeDasharray: from };\n        }\n\n        const { radius: _, ...otherPathProps } = svgPropertiesAndEvents(props);\n\n        return (\n          <path\n            {...otherPathProps}\n            radius={typeof radius === 'number' ? radius : undefined}\n            className={layerClass}\n            d={getRectanglePath(currX, currY, currWidth, currHeight, radius)}\n            ref={pathRef}\n            style={{\n              ...animationStyle,\n              ...props.style,\n            }}\n          />\n        );\n      }}\n    </JavascriptAnimate>\n  );\n};\n","import { ChartOffsetInternal, RelativePointer, Coordinate, PolarViewBoxRequired, RangeObj } from './types';\n\nexport const RADIAN = Math.PI / 180;\n\nexport const degreeToRadian = (angle: number) => (angle * Math.PI) / 180;\n\nexport const radianToDegree = (angleInRadian: number) => (angleInRadian * 180) / Math.PI;\n\nexport const polarToCartesian = (cx: number, cy: number, radius: number, angle: number): Coordinate => ({\n  x: cx + Math.cos(-RADIAN * angle) * radius,\n  y: cy + Math.sin(-RADIAN * angle) * radius,\n});\n\nexport const getMaxRadius = (\n  width: number,\n  height: number,\n  offset: ChartOffsetInternal = {\n    top: 0,\n    right: 0,\n    bottom: 0,\n    left: 0,\n    width: 0,\n    height: 0,\n    brushBottom: 0,\n  },\n) =>\n  Math.min(\n    Math.abs(width - (offset.left || 0) - (offset.right || 0)),\n    Math.abs(height - (offset.top || 0) - (offset.bottom || 0)),\n  ) / 2;\n\nconst distanceBetweenPoints = (point: Coordinate, anotherPoint: Coordinate) => {\n  const { x: x1, y: y1 } = point;\n  const { x: x2, y: y2 } = anotherPoint;\n\n  return Math.sqrt((x1 - x2) ** 2 + (y1 - y2) ** 2);\n};\n\nconst getAngleOfPoint = ({ x, y }: Coordinate, { cx, cy }: PolarViewBoxRequired) => {\n  const radius = distanceBetweenPoints({ x, y }, { x: cx, y: cy });\n\n  if (radius <= 0) {\n    return { radius, angle: 0 };\n  }\n\n  const cos = (x - cx) / radius;\n  let angleInRadian = Math.acos(cos);\n\n  if (y > cy) {\n    angleInRadian = 2 * Math.PI - angleInRadian;\n  }\n\n  return { radius, angle: radianToDegree(angleInRadian), angleInRadian };\n};\n\nconst formatAngleOfSector = ({ startAngle, endAngle }: PolarViewBoxRequired) => {\n  const startCnt = Math.floor(startAngle / 360);\n  const endCnt = Math.floor(endAngle / 360);\n  const min = Math.min(startCnt, endCnt);\n\n  return {\n    startAngle: startAngle - min * 360,\n    endAngle: endAngle - min * 360,\n  };\n};\n\nconst reverseFormatAngleOfSector = (angle: number, { startAngle, endAngle }: PolarViewBoxRequired): number => {\n  const startCnt = Math.floor(startAngle / 360);\n  const endCnt = Math.floor(endAngle / 360);\n  const min = Math.min(startCnt, endCnt);\n\n  return angle + min * 360;\n};\n\nexport const inRangeOfSector = (\n  { relativeX: x, relativeY: y }: RelativePointer,\n  viewBox: PolarViewBoxRequired,\n): RangeObj | null => {\n  const { radius, angle } = getAngleOfPoint({ x, y }, viewBox);\n  const { innerRadius, outerRadius } = viewBox;\n\n  if (radius < innerRadius || radius > outerRadius) {\n    return null;\n  }\n\n  if (radius === 0) {\n    return null;\n  }\n\n  const { startAngle, endAngle } = formatAngleOfSector(viewBox);\n  let formatAngle = angle;\n  let inRange;\n\n  if (startAngle <= endAngle) {\n    while (formatAngle > endAngle) {\n      formatAngle -= 360;\n    }\n    while (formatAngle < startAngle) {\n      formatAngle += 360;\n    }\n    inRange = formatAngle >= startAngle && formatAngle <= endAngle;\n  } else {\n    while (formatAngle > startAngle) {\n      formatAngle -= 360;\n    }\n    while (formatAngle < endAngle) {\n      formatAngle += 360;\n    }\n    inRange = formatAngle >= endAngle && formatAngle <= startAngle;\n  }\n\n  if (inRange) {\n    return { ...viewBox, radius, angle: reverseFormatAngleOfSector(formatAngle, viewBox) };\n  }\n\n  return null;\n};\n","import { polarToCartesian } from '../PolarUtils';\nimport { Coordinate, PolarCoordinate } from '../types';\n\nexport type RadialCursorPoints = {\n  points: [startPoint: Coordinate, endPoint: Coordinate];\n  cx?: number;\n  cy?: number;\n  radius?: number;\n  startAngle?: number;\n  endAngle?: number;\n};\n\n/**\n * Only applicable for radial layouts\n * @param {Object} activeCoordinate ChartCoordinate\n * @returns {Object} RadialCursorPoints\n */\nexport function getRadialCursorPoints(activeCoordinate: PolarCoordinate): RadialCursorPoints {\n  const { cx, cy, radius, startAngle, endAngle } = act