d from data. Can be undefined, as an option for performance optimization\n * @param allowDataOverflow provided by users. If true then the data domain wins\n *\n * @return [min, max] domain if it's well-formed; undefined if the domain is invalid\n */\nexport function parseNumericalUserDomain(\n  userDomain: AxisDomain | undefined,\n  dataDomain: NumberDomain | undefined,\n  allowDataOverflow: boolean,\n): NumberDomain | undefined {\n  if (!allowDataOverflow && dataDomain == null) {\n    // Cannot compute data overflow if the data is not provided\n    return undefined;\n  }\n  if (typeof userDomain === 'function' && dataDomain != null) {\n    try {\n      const result = userDomain(dataDomain, allowDataOverflow);\n      if (isWellFormedNumberDomain(result)) {\n        return extendDomain(result, dataDomain, allowDataOverflow);\n      }\n    } catch {\n      /* ignore the exception and compute domain from data later */\n    }\n  }\n  if (Array.isArray(userDomain) && userDomain.length === 2) {\n    const [providedMin, providedMax] = userDomain;\n    let finalMin, finalMax: string | number | undefined;\n\n    if (providedMin === 'auto') {\n      if (dataDomain != null) {\n        finalMin = Math.min(...dataDomain);\n      }\n    } else if (isNumber(providedMin)) {\n      finalMin = providedMin;\n    } else if (typeof providedMin === 'function') {\n      try {\n        if (dataDomain != null) {\n          finalMin = providedMin(dataDomain?.[0]);\n        }\n      } catch {\n        /* ignore the exception and compute domain from data later */\n      }\n    } else if (typeof providedMin === 'string' && MIN_VALUE_REG.test(providedMin)) {\n      const match = MIN_VALUE_REG.exec(providedMin);\n      if (match == null || match[1] == null || dataDomain == null) {\n        finalMin = undefined;\n      } else {\n        const value = +match[1];\n        finalMin = dataDomain[0] - value;\n      }\n    } else {\n      finalMin = dataDomain?.[0];\n    }\n\n    if (providedMax === 'auto') {\n      if (dataDomain != null) {\n        finalMax = Math.max(...dataDomain);\n      }\n    } else if (isNumber(providedMax)) {\n      finalMax = providedMax;\n    } else if (typeof providedMax === 'function') {\n      try {\n        if (dataDomain != null) {\n          finalMax = providedMax(dataDomain?.[1]);\n        }\n      } catch {\n        /* ignore the exception and compute domain from data later */\n      }\n    } else if (typeof providedMax === 'string' && MAX_VALUE_REG.test(providedMax)) {\n      const match = MAX_VALUE_REG.exec(providedMax);\n      if (match == null || match[1] == null || dataDomain == null) {\n        finalMax = undefined;\n      } else {\n        const value = +match[1];\n        finalMax = dataDomain[1] + value;\n      }\n    } else {\n      finalMax = dataDomain?.[1];\n    }\n\n    const candidate = [finalMin, finalMax];\n    if (isWellFormedNumberDomain(candidate)) {\n      if (dataDomain == null) {\n        return candidate;\n      }\n      return extendDomain(candidate, dataDomain, allowDataOverflow);\n    }\n  }\n  return undefined;\n}\n","/**\n * @fileOverview Some common arithmetic methods\n * @author xile611\n * @date 2015-09-17\n */\nimport Decimal from 'decimal.js-light';\n\n/**\n * Get the digit count of a number.\n * If the absolute value is in the interval [0.1, 1), the result is 0.\n * If the absolute value is in the interval [0.01, 0.1), the digit count is -1.\n * If the absolute value is in the interval [0.001, 0.01), the digit count is -2.\n *\n * @param  {Number} value The number\n * @return {Integer}      Digit count\n */\nfunction getDigitCount(value: number) {\n  let result;\n\n  if (value === 0) {\n    result = 1;\n  } else {\n    result = Math.floor(new Decimal(value).abs().log(10).toNumber()) + 1;\n  }\n\n  return result;\n}\n\n/**\n * Get the data in the interval [start, end) with a fixed step.\n * Also handles JS calculation precision issues.\n *\n * @param  {Decimal} start Start point\n * @param  {Decimal} end   End point, not included\n * @param  {Decimal} step  Step size\n * @return {Array}         Array of numbers\n */\nfunction rangeStep(start: Decimal, end: Decimal, step: Decimal): Array<number> {\n  let num = new Decimal(start);\n  let i = 0;\n  const result: Array<number> = [];\n\n  // magic number to prevent infinite loop\n  while (num.lt(end) && i < 100000) {\n    result.push(num.toNumber());\n\n    num = num.add(step);\n    i++;\n  }\n\n  return result;\n}\n\nexport { rangeStep, getDigitCount };\n","/**\n * @fileOverview calculate tick values of scale\n * @author xile611, arcthur\n * @date 2015-09-17\n */\nimport Decimal from 'decimal.js-light';\nimport { getDigitCount, rangeStep } from './util/arithmetic';\nimport { NumberDomain } from '../types';\nimport { NiceTicksAlgorithm } from '../../state/cartesianAxisSlice';\n\n/**\n * Calculate a interval of a minimum value and a maximum value\n *\n * @param  {Number} min       The minimum value\n * @param  {Number} max       The maximum value\n * @return {Array} An interval\n */\nexport const getValidInterval = ([min, max]: [number, number]): [number, number] => {\n  let [validMin, validMax] = [min, max];\n\n  // exchange\n  if (min > max) {\n    [validMin, validMax] = [max, min];\n  }\n\n  return [validMin, validMax];\n};\n\n/**\n * Calculate the step which is easy to understand between ticks, like 10, 20, 25\n *\n * @param  roughStep        The rough step calculated by dividing the difference by the tickCount\n * @param  allowDecimals    Allow the ticks to be decimals or not\n * @param  correctionFactor A correction factor\n * @return The step which is easy to understand between two ticks\n */\nexport const getAdaptiveStep = (roughStep: Decimal, allowDecimals: boolean, correctionFactor: number) => {\n  if (roughStep.lte(0)) {\n    return new Decimal(0);\n  }\n\n  const digitCount = getDigitCount(roughStep.toNumber());\n  // The ratio between the rough step and the smallest number which has a bigger\n  // order of magnitudes than the rough step\n  const digitCountValue = new Decimal(10).pow(digitCount);\n  const stepRatio = roughStep.div(digitCountValue);\n  // When an integer and a float multiplied, the accuracy of result may be wrong\n  const stepRatioScale = digitCount !== 1 ? 0.05 : 0.1;\n  const amendStepRatio = new Decimal(Math.ceil(stepRatio.div(stepRatioScale).toNumber()))\n    .add(correctionFactor)\n    .mul(stepRatioScale);\n\n  const formatStep = amendStepRatio.mul(digitCountValue);\n\n  return allowDecimals ? new Decimal(formatStep.toNumber()) : new Decimal(Math.ceil(formatStep.toNumber()));\n};\n\ntype StepFunction = (roughStep: Decimal, allowDecimals: boolean, correctionFactor: number) => Decimal;\n\n/**\n * The snap125 step algorithm snaps to nice numbers (1, 2, 2.5, 5) at each\n * order of magnitude, producing human-friendly tick intervals like\n * 0, 5, 10, 15, 20 instead of 0, 4, 8, 12, 16.\n *\n * This is opt-in and can be enabled via the `niceTicks` prop on axis components.\n *\n * @param  roughStep        The rough step calculated by dividing the difference by the tickCount\n * @param  allowDecimals    Allow the ticks to be decimals or not\n * @param  correctionFactor A correction factor\n * @return The step which is easy to understand between two ticks\n */\nexport const getSnap125Step: StepFunction = (roughStep: Decimal, allowDecimals: boolean, correctionFactor: number) => {\n  if (roughStep.lte(0)) {\n    return new Decimal(0);\n  }\n\n  const NICE_STEPS = [1, 2, 2.5, 5];\n\n  const roughNum = roughStep.toNumber();\n  const exponent = Math.floor(new Decimal(roughNum).abs().log(10).toNumber());\n  let magnitude = new Decimal(10).pow(exponent);\n\n  // normalized is in the range [1, 10)\n  const normalized = roughStep.div(magnitude).toNumber();\n\n  // Find the smallest nice step >= normalized (ceiling)\n  let niceIdx = NICE_STEPS.findIndex(s => s >= normalized - 1e-10);\n  if (niceIdx === -1) {\n    // normalized > 5 (e.g. 7.3), move to next order of magnitude\n    magnitude = magnitude.mul(10);\n    niceIdx = 0;\n  }\n\n  // Apply correction factor by stepping through the nice number sequence\n  niceIdx += correctionFactor;\n  if (niceIdx >= NICE_STEPS.length) {\n    const extraMag = Math.floor(niceIdx / NICE_STEPS.length);\n    niceIdx %= NICE_STEPS.length;\n    magnitude = magnitude.mul(new Decimal(10).pow(extraMag));\n  }\n\n  const niceStep = NICE_STEPS[niceIdx] ?? 1;\n  const formatStep = new Decimal(niceStep).mul(magnitude);\n\n  return allowDecimals ? formatStep : new Decimal(Math.ceil(formatStep.toNumber()));\n};\n\n/**\n * calculate the ticks when the minimum value equals to the maximum value\n *\n * @param  value         The minimum value which is also the maximum value\n * @param  tickCount     The count of ticks\n * @param  allowDecimals Allow the ticks to be decimals or not\n * @return array of ticks\n */\nexport const getTickOfSingleValue = (value: number, tickCount: number, allowDecimals: boolean): Array<number> => {\n  let step: Decimal = new Decimal(1);\n  // calculate the middle value of ticks\n  let middle = new Decimal(value);\n\n  if (!middle.isint() && allowDecimals) {\n    const absVal = Math.abs(value);\n\n    if (absVal < 1) {\n      // The step should be a float number when the difference is smaller than 1\n      step = new Decimal(10).pow(getDigitCount(value) - 1);\n\n      middle = new Decimal(Math.floor(middle.div(step).toNumber())).mul(step);\n    } else if (absVal > 1) {\n      // Return the maximum integer which is smaller than 'value' when 'value' is greater than 1\n      middle = new Decimal(Math.floor(value));\n    }\n  } else if (value === 0) {\n    middle = new Decimal(Math.floor((tickCount - 1) / 2));\n  } else if (!allowDecimals) {\n    middle = new Decimal(Math.floor(value));\n  }\n\n  const middleIndex = Math.floor((tickCount - 1) / 2);\n  const ticks: Array<number> = [];\n\n  for (let i = 0; i < tickCount; i++) {\n    ticks.push(middle.add(new Decimal(i - middleIndex).mul(step)).toNumber());\n  }\n\n  return ticks;\n};\n\n/**\n * Calculate the step\n *\n * @param  min              The minimum value of an interval\n * @param  max              The maximum value of an interval\n * @param  tickCount        The count of ticks\n * @param  allowDecimals    Allow the ticks to be decimals or not\n * @param  correctionFactor A correction factor\n * @return The step, minimum value of ticks, maximum value of ticks\n */\nexport const calculateStep = (\n  min: number,\n  max: number,\n  tickCount: number,\n  allowDecimals: boolean,\n  correctionFactor: number = 0,\n  stepFn: StepFunction = getAdaptiveStep,\n): {\n  step: Decimal;\n  tickMin: Decimal;\n  tickMax: Decimal;\n} => {\n  // dirty hack (for recharts' test)\n  if (!Number.isFinite((max - min) / (tickCount - 1))) {\n    return {\n      step: new Decimal(0),\n      tickMin: new Decimal(0),\n      tickMax: new Decimal(0),\n    };\n  }\n\n  // The step which is easy to understand between two ticks\n  const step = stepFn(new Decimal(max).sub(min).div(tickCount - 1), allowDecimals, correctionFactor);\n\n  // A medial value of ticks\n  let middle;\n\n  // When 0 is inside the interval, 0 should be a tick\n  if (min <= 0 && max >= 0) {\n    middle = new Decimal(0);\n  } else {\n    // calculate the middle value\n    middle = new Decimal(min).add(max).div(2);\n    // minus modulo value\n    middle = middle.sub(new Decimal(middle).mod(step));\n  }\n\n  let belowCount = Math.ceil(middle.sub(min).div(step).toNumber());\n  let upCount = Math.ceil(new Decimal(max).sub(middle).div(step).toNumber());\n  const scaleCount = belowCount + upCount + 1;\n\n  if (scaleCount > tickCount) {\n    // When more ticks need to cover the interval, step should be bigger.\n    return calculateStep(min, max, tickCount, allowDecimals, correctionFactor + 1, stepFn);\n  }\n  if (scaleCount < tickCount) {\n    // When less ticks can cover the interval, we should add some additional ticks\n    upCount = max > 0 ? upCount + (tickCount - scaleCount) : upCount;\n    belowCount = max > 0 ? belowCount : belowCount + (tickCount - scaleCount);\n  }\n\n  return {\n    step,\n    tickMin: middle.sub(new Decimal(belowCount).mul(step)),\n    tickMax: middle.add(new Decimal(upCount).mul(step)),\n  };\n};\n\n/**\n * Calculate the ticks of an interval. Ticks can appear outside the interval\n * if it makes them more rounded and nice.\n *\n * @param tuple of [min,max] min: The minimum value, max: The maximum value\n * @param tickCount     The count of ticks\n * @param allowDecimals Allow the ticks to be decimals or not\n * @param niceTicksMode The algorithm to use for calculating nice ticks.\n * @return array of ticks\n */\nexport const getNiceTickValues = (\n  [min, max]: NumberDomain,\n  tickCount = 6,\n  allowDecimals = true,\n  niceTicksMode: NiceTicksAlgorithm = 'auto',\n): number[] => {\n  // More than two ticks should be return\n  const count = Math.max(tickCount, 2);\n  const [cormin, cormax] = getValidInterval([min, max]);\n\n  if (cormin === -Infinity || cormax === Infinity) {\n    const values: Array<number> =\n      cormax === Infinity\n        ? [cormin, ...Array(tickCount - 1).fill(Infinity)]\n        : [...Array(tickCount - 1).fill(-Infinity), cormax];\n\n    return min > max ? values.reverse() : values;\n  }\n\n  if (cormin === cormax) {\n    return getTickOfSingleValue(cormin, tickCount, allowDecimals);\n  }\n\n  const stepFn = niceTicksMode === 'snap125' ? getSnap125Step : getAdaptiveStep;\n\n  // Get the step between two ticks\n  const { step, tickMin, tickMax } = calculateStep(cormin, cormax, count, allowDecimals, 0, stepFn);\n\n  const values = rangeStep(tickMin, tickMax.add(new Decimal(0.1).mul(step)), step);\n\n  return min > max ? values.reverse() : values;\n};\n\n/**\n * Calculate the ticks of an interval.\n * Ticks will be constrained to the interval [min, max] even if it makes them less rounded and nice.\n *\n * @param tuple of [min,max] min: The minimum value, max: The maximum value\n * @param tickCount     The count of ticks. This function may return less than tickCount ticks if the interval is too small.\n * @param allowDecimals Allow the ticks to be decimals or not\n * @param niceTicksMode          The algorithm to use for calculating nice ticks. See {@link NiceTicksAlgorithm}.\n * @return array of ticks\n */\nexport const getTickValuesFixedDomain = (\n  [min, max]: NumberDomain,\n  tickCount: number,\n  allowDecimals = true,\n  niceTicksMode: NiceTicksAlgorithm = 'auto',\n) => {\n  // More than two ticks should be return\n  const [cormin, cormax] = getValidInterval([min, max]);\n\n  if (cormin === -Infinity || cormax === Infinity) {\n    return [min, max];\n  }\n\n  if (cormin === cormax) {\n    return [cormin];\n  }\n\n  const stepFn = niceTicksMode === 'snap125' ? getSnap125Step : getAdaptiveStep;\n  const count = Math.max(tickCount, 2);\n  const step = stepFn(new Decimal(cormax).sub(cormin).div(count - 1), allowDecimals, 0);\n  let values = [...rangeStep(new Decimal(cormin), new Decimal(cormax), step), cormax];\n\n  if (allowDecimals === false) {\n    /*\n     * allowDecimals is false means that we want to have integer ticks.\n     * The step is guaranteed to be an integer in the code above which is great start\n     * but when the first step is not an integer, it will start stepping from a decimal value anyway.\n     * So we need to round all the values to integers after the fact.\n     * The domain boundary (cormax) is appended after the rangeStep values. When\n     * cormax rounds down to the same integer as the last rangeStep value, we end up\n     * with a duplicate trailing tick. Remove it.\n     */\n    values = values.map(value => Math.round(value));\n    const last = values.length - 1;\n    if (last > 0 && values[last] === values[last - 1]) {\n      values = values.slice(0, last);\n    }\n  }\n\n  return min > max ? values.reverse() : values;\n};\n","import { RechartsRootState } from '../store';\nimport { StackOffsetType } from '../../util/types';\nimport { SyncMethod } from '../../synchronisation/types';\nimport { BaseValue } from '../../cartesian/Area';\n\nexport const selectRootMaxBarSize = (state: RechartsRootState): number | undefined => state.rootProps.maxBarSize;\nexport const selectBarGap = (state: RechartsRootState): string | number => state.rootProps.barGap;\nexport const selectBarCategoryGap = (state: RechartsRootState): string | number => state.rootProps.barCategoryGap;\nexport const selectRootBarSize = (state: RechartsRootState): string | number | undefined => state.rootProps.barSize;\nexport const selectStackOffsetType = (state: RechartsRootState): StackOffsetType => state.rootProps.stackOffset;\nexport const selectReverseStackOrder = (state: RechartsRootState): boolean => state.rootProps.reverseStackOrder;\nexport const selectChartName = (state: RechartsRootState) => state.options.chartName;\n\nexport const selectSyncId = (state: RechartsRootState) => state.rootProps.syncId;\nexport const selectSyncMethod = (state: RechartsRootState): SyncMethod => state.rootProps.syncMethod;\nexport const selectEventEmitter = (state: RechartsRootState) => state.options.eventEmitter;\nexport const selectChartBaseValue: (state: RechartsRootState) => BaseValue | undefined = (state: RechartsRootState) =>\n  state.rootProps.baseValue;\n","/**\n * A collection of all default zIndex values used by Recharts.\n *\n * You can reuse these, or you can define your own.\n */\nexport const DefaultZIndexes = {\n  /**\n   * CartesianGrid and PolarGrid\n   */\n  grid: -100,\n  /**\n   * Background of Bar and RadialBar.\n   * This is not visible by default but can be enabled by setting background={true} on Bar or RadialBar.\n   */\n  barBackground: -50,\n\n  /*\n   * other chart elements or custom elements without specific zIndex\n   * render in here, at zIndex 0\n   */\n\n  /**\n   * Area, Pie, Radar, and ReferenceArea\n   */\n  area: 100,\n\n  /**\n   * Cursor is embedded inside Tooltip and controlled by it.\n   * The Tooltip itself has a separate portal and is not included in the zIndex system;\n   * Cursor is the decoration inside the chart area. CursorRectangle is a rectangle box.\n   * It renders below bar so that in a stacked bar chart the cursor rectangle does not hide the other bars.\n   */\n  cursorRectangle: 200,\n\n  /**\n   * Bar and RadialBar\n   */\n  bar: 300,\n\n  /**\n   * Line and ReferenceLine, and ErrorBor\n   */\n  line: 400,\n\n  /**\n   * XAxis and YAxis and PolarAngleAxis and PolarRadiusAxis ticks and lines and children\n   */\n  axis: 500,\n\n  /**\n   * Scatter and ReferenceDot,\n   * and Dots of Line and Area and Radar if they have dot=true\n   */\n  scatter: 600,\n\n  /**\n   * Hovering over a Bar or RadialBar renders a highlight rectangle\n   */\n  activeBar: 1000,\n\n  /**\n   * Cursor is embedded inside Tooltip and controlled by it.\n   * The Tooltip itself has a separate portal and is not included in the zIndex system;\n   * Cursor is the decoration inside the chart area, usually a cross or a box.\n   * CursorLine is a line cursor rendered in Line, Area, Scatter, Radar charts.\n   * It renders above the Line and Scatter so that it is always visible.\n   * It renders below active dot so that the dot is always visible and shows the current point.\n   * We're also assuming that the active dot is small enough that it does not fully cover the cursor line.\n   *\n   * This also applies to the radial cursor in RadialBarChart.\n   */\n  cursorLine: 1100,\n\n  /**\n   * Hovering over a Point in Line, Area, Scatter, Radar renders a highlight dot\n   */\n  activeDot: 1200,\n\n  /**\n   * LabelList and Label, including Axis labels\n   */\n  label: 2000,\n} as const satisfies Record<string, number>;\n","import { Props } from './PolarAngleAxis';\nimport { DefaultZIndexes } from '../zIndex/DefaultZIndexes';\n\nexport const defaultPolarAngleAxisProps = {\n  allowDecimals: false,\n  allowDuplicatedCategory: true, // if I set this to false then Tooltip synchronisation stops working in Radar, wtf\n  allowDataOverflow: false,\n  angle: 0,\n  angleAxisId: 0,\n  axisLine: true,\n  axisLineType: 'polygon',\n  cx: 0,\n  cy: 0,\n  hide: false,\n  includeHidden: false,\n  label: false,\n  niceTicks: 'auto',\n  orientation: 'outer',\n  reversed: false,\n  scale: 'auto',\n  tick: true,\n  tickLine: true,\n  tickSize: 8,\n  type: 'auto',\n  zIndex: DefaultZIndexes.axis,\n} as const satisfies Props;\n","import { Props } from './PolarRadiusAxis';\nimport { DefaultZIndexes } from '../zIndex/DefaultZIndexes';\n\nexport const defaultPolarRadiusAxisProps = {\n  allowDataOverflow: false,\n  allowDecimals: false,\n  allowDuplicatedCategory: true,\n  angle: 0,\n  axisLine: true,\n  includeHidden: false,\n  hide: false,\n  niceTicks: 'auto',\n  label: false,\n  orientation: 'right',\n  radiusAxisId: 0,\n  reversed: false,\n  scale: 'auto',\n  stroke: '#ccc',\n  tick: true,\n  tickCount: 5,\n  tickLine: true,\n  type: 'auto',\n  zIndex: DefaultZIndexes.axis,\n} as const satisfies Props;\n","import { BaseCartesianAxis } from '../../cartesianAxisSlice';\nimport { AxisRange } from '../axisSelectors';\n\nexport const combineAxisRangeWithReverse = (\n  axisSettings: BaseCartesianAxis | undefined,\n  axisRange: AxisRange | undefined,\n): AxisRange | undefined => {\n  if (!axisSettings || !axisRange) {\n    return undefined;\n  }\n  if (axisSettings?.reversed) {\n    return [axisRange[1], axisRange[0]];\n  }\n  return axisRange;\n};\n","import { AxisDomainTypeInput, AxisType, EvaluatedAxisDomainType, LayoutType } from './types';\nimport { isCategoricalAxis } from './ChartUtils';\n\n/**\n * This function evaluates the \"auto\" axis domain type based on the chart layout and axis type.\n * It outputs a definitive axis domain type that can be used for further processing.\n */\nexport function getAxisTypeBasedOnLayout(\n  layout: LayoutType | undefined,\n  axisType: AxisType,\n  axisDomainType: AxisDomainTypeInput,\n): EvaluatedAxisDomainType | undefined {\n  if (axisDomainType !== 'auto') {\n    return axisDomainType;\n  }\n  if (layout == null) {\n    return undefined;\n  }\n  return isCategoricalAxis(layout, axisType) ? 'category' : 'number';\n}\n","import { createSelector } from 'reselect';\nimport { RechartsRootState } from '../store';\nimport { AxisId } from '../cartesianAxisSlice';\nimport { AngleAxisSettings, RadiusAxisSettings } from '../polarAxisSlice';\nimport { PolarChartOptions } from '../polarOptionsSlice';\nimport { selectChartHeight, selectChartWidth } from './containerSelectors';\nimport { selectChartOffsetInternal } from './selectChartOffsetInternal';\nimport { getMaxRadius } from '../../util/PolarUtils';\nimport { getPercentValue } from '../../util/DataUtils';\nimport { AxisDomainTypeInput, LayoutType, PolarLayout, PolarViewBoxRequired } from '../../util/types';\nimport { defaultPolarAngleAxisProps } from '../../polar/defaultPolarAngleAxisProps';\nimport { defaultPolarRadiusAxisProps } from '../../polar/defaultPolarRadiusAxisProps';\nimport { AxisRange } from './axisSelectors';\nimport { combineAxisRangeWithReverse } from './combiners/combineAxisRangeWithReverse';\nimport { selectChartLayout, selectPolarChartLayout } from '../../context/chartLayoutContext';\nimport { getAxisTypeBasedOnLayout } from '../../util/getAxisTypeBasedOnLayout';\n\nexport const implicitAngleAxis: Omit<AngleAxisSettings, 'type'> & { type: AxisDomainTypeInput } = {\n  allowDataOverflow: defaultPolarAngleAxisProps.allowDataOverflow,\n  allowDecimals: defaultPolarAngleAxisProps.allowDecimals,\n  allowDuplicatedCategory: false, // defaultPolarAngleAxisProps.allowDuplicatedCategory has it set to true but the actual axis rendering ignores the prop because reasons,\n  dataKey: undefined,\n  domain: undefined,\n  id: defaultPolarAngleAxisProps.angleAxisId,\n  includeHidden: false,\n  name: undefined,\n  reversed: defaultPolarAngleAxisProps.reversed,\n  scale: defaultPolarAngleAxisProps.scale,\n  tick: defaultPolarAngleAxisProps.tick,\n  tickCount: undefined,\n  ticks: undefined,\n  type: defaultPolarAngleAxisProps.type,\n  unit: undefined,\n  niceTicks: 'auto',\n};\n\nexport const implicitRadiusAxis: Omit<RadiusAxisSettings, 'type'> & { type: AxisDomainTypeInput } = {\n  allowDataOverflow: defaultPolarRadiusAxisProps.allowDataOverflow,\n  allowDecimals: defaultPolarRadiusAxisProps.allowDecimals,\n  allowDuplicatedCategory: defaultPolarRadiusAxisProps.allowDuplicatedCategory,\n  dataKey: undefined,\n  domain: undefined,\n  id: defaultPolarRadiusAxisProps.radiusAxisId,\n  includeHidden: defaultPolarRadiusAxisProps.includeHidden,\n  name: undefined,\n  reversed: defaultPolarRadiusAxisProps.reversed,\n  scale: defaultPolarRadiusAxisProps.scale,\n  tick: defaultPolarRadiusAxisProps.tick,\n  tickCount: defaultPolarRadiusAxisProps.tickCount,\n  ticks: undefined,\n  type: defaultPolarRadiusAxisProps.type,\n  unit: undefined,\n  niceTicks: 'auto',\n};\n\nconst selectAngleAxisNoDefaults = (\n  state: RechartsRootState,\n  angleAxisId: AxisId | undefined,\n): AngleAxisSettings | undefined => {\n  if (angleAxisId == null) {\n    return undefined;\n  }\n  return state.polarAxis.angleAxis[angleAxisId];\n};\n\nexport const selectAngleAxis: (state: RechartsRootState, angleAxisId: AxisId | undefined) => AngleAxisSettings =\n  createSelector(\n    [selectAngleAxisNoDefaults, selectPolarChartLayout],\n    (angleAxisSettings, layout: PolarLayout | undefined): AngleAxisSettings => {\n      if (angleAxisSettings != null) {\n        return angleAxisSettings;\n      }\n      const evaluatedType = getAxisTypeBasedOnLayout(layout, 'angleAxis', implicitAngleAxis.type) ?? 'category';\n      return {\n        ...implicitAngleAxis,\n        type: evaluatedType,\n      };\n    },\n  );\n\nconst selectRadiusAxisNoDefaults = (state: RechartsRootState, radiusAxisId: AxisId): RadiusAxisSettings | undefined => {\n  return state.polarAxis.radiusAxis[radiusAxisId];\n};\n\nexport const selectRadiusAxis: (state: RechartsRootState, radiusAxisId: AxisId) => RadiusAxisSettings = createSelector(\n  [selectRadiusAxisNoDefaults, selectPolarChartLayout],\n  (radiusAxisSettings, layout: PolarLayout | undefined): RadiusAxisSettings => {\n    if (radiusAxisSettings != null) {\n      return radiusAxisSettings;\n    }\n    const evaluatedType = getAxisTypeBasedOnLayout(layout, 'radiusAxis', implicitRadiusAxis.type) ?? 'category';\n    return {\n      ...implicitRadiusAxis,\n      type: evaluatedType,\n    };\n  },\n);\n\nexport const selectPolarOptions = (state: RechartsRootState): PolarChartOptions | null => state.polarOptions;\n\nexport const selectMaxRadius: (state: RechartsRootState) => number = createSelector(\n  [selectChartWidth, selectChartHeight, selectChartOffsetInternal],\n  getMaxRadius,\n);\n\nconst selectInnerRadius: (state: RechartsRootState) => number | undefined = createSelector(\n  [selectPolarOptions, selectMaxRadius],\n  (polarChartOptions: PolarChartOptions | null, maxRadius: number) => {\n    if (polarChartOptions == null) {\n      return undefined;\n    }\n    return getPercentValue(polarChartOptions.innerRadius, maxRadius, 0);\n  },\n);\n\nexport const selectOuterRadius: (state: RechartsRootState) => number | undefined = createSelector(\n  [selectPolarOptions, selectMaxRadius],\n  (polarChartOptions: PolarChartOptions | null, maxRadius: number) => {\n    if (polarChartOptions == null) {\n      return undefined;\n    }\n    return getPercentValue(polarChartOptions.outerRadius, maxRadius, maxRadius * 0.8);\n  },\n);\n\nconst combineAngleAxisRange = (polarOptions: PolarChartOptions | null): AxisRange => {\n  if (polarOptions == null) {\n    return [0, 0];\n  }\n  const { startAngle, endAngle } = polarOptions;\n  return [startAngle, endAngle];\n};\n\nexport const selectAngleAxisRange: (state: RechartsRootState) => AxisRange = createSelector(\n  [selectPolarOptions],\n  combineAngleAxisRange,\n);\n\nexport const selectAngleAxisRangeWithReversed: (\n  state: RechartsRootState,\n  angleAxisId: AxisId,\n) => AxisRange | undefined = createSelector([selectAngleAxis, selectAngleAxisRange], combineAxisRangeWithReverse);\n\nexport const selectRadiusAxisRange: (state: RechartsRootState, radiusAxisId: AxisId) => AxisRange | undefined =\n  createSelector([selectMaxRadius, selectInnerRadius, selectOuterRadius], (maxRadius, innerRadius, outerRadius) => {\n    if (maxRadius == null || innerRadius == null || outerRadius == null) {\n      return undefined;\n    }\n    return [innerRadius, outerRadius];\n  });\n\nexport const selectRadiusAxisRangeWithReversed: (\n  state: RechartsRootState,\n  radiusAxisId: AxisId,\n) => AxisRange | undefined = createSelector([selectRadiusAxis, selectRadiusAxisRange], combineAxisRangeWithReverse);\n\nexport const selectPolarViewBox: (state: RechartsRootState) => PolarViewBoxRequired | undefined = createSelector(\n  [selectChartLayout, selectPolarOptions, selectInnerRadius, selectOuterRadius, selectChartWidth, selectChartHeight],\n  (\n    layout: LayoutType,\n    polarOptions: PolarChartOptions | null,\n    innerRadius,\n    outerRadius,\n    width,\n    height,\n  ): PolarViewBoxRequired | undefined => {\n    if (\n      (layout !== 'centric' && layout !== 'radial') ||\n      polarOptions == null ||\n      innerRadius == null ||\n      outerRadius == null\n    ) {\n      return undefined;\n    }\n    const { cx, cy, startAngle, endAngle } = polarOptions;\n    return {\n      cx: getPercentValue(cx, width, width / 2),\n      cy: getPercentValue(cy, height, height / 2),\n      innerRadius,\n      outerRadius,\n      startAngle,\n      endAngle,\n      clockWise: false, // this property look useful, why not use it?\n    };\n  },\n);\n","import { RechartsRootState } from '../store';\n\nexport const pickAxisType = <T>(_state: RechartsRootState, axisType: T): T => axisType;\n","import { RechartsRootState } from '../store';\nimport { AxisId } from '../cartesianAxisSlice';\n\nexport const pickAxisId = (_state: RechartsRootState, _axisType: unknown, axisId: AxisId): AxisId => axisId;\n","import { StackSeriesIdentifier } from './stackTypes';\nimport { MaybeStackedGraphicalItem } from '../../state/types/StackedGraphicalItem';\n\nexport function getStackSeriesIdentifier(graphicalItem: MaybeStackedGraphicalItem): StackSeriesIdentifier;\nexport function getStackSeriesIdentifier(graphicalItem: undefined): undefined;\nexport function getStackSeriesIdentifier(\n  graphicalItem: MaybeStackedGraphicalItem | undefined,\n): StackSeriesIdentifier | undefined;\n/**\n * Returns identifier for stack series which is one individual graphical item in the stack.\n * @param graphicalItem - The graphical item representing the series in the stack.\n * @return The identifier for the series in the stack\n */\nexport function getStackSeriesIdentifier(\n  graphicalItem: MaybeStackedGraphicalItem | undefined,\n): StackSeriesIdentifier | undefined {\n  return graphicalItem?.id;\n}\n","import { ChartDataState } from '../../chartDataSlice';\nimport { BaseCartesianAxis } from '../../cartesianAxisSlice';\nimport { getStackSeriesIdentifier } from '../../../util/stacks/getStackSeriesIdentifier';\nimport { getValueByDataKey } from '../../../util/ChartUtils';\nimport { StackSeriesIdentifier } from '../../../util/stacks/stackTypes';\nimport { DefinitelyStackedGraphicalItem } from '../../types/StackedGraphicalItem';\n\n/**\n * In a stacked chart, each graphical item has its own data. That data could be either:\n * - defined on the chart root, in which case the item gets a unique dataKey\n * - or defined on the item itself, in which case multiple items can share the same dataKey\n *\n * That means we cannot use the dataKey as a unique identifier for the item.\n *\n * This type represents a single data point in a stacked chart, where each key is a series identifier\n * and the value is the numeric value for that series using the numerical axis dataKey.\n */\nexport type DisplayedStackedDataPoint = Record<StackSeriesIdentifier, number>;\n\nexport type DisplayedStackedData = ReadonlyArray<DisplayedStackedDataPoint>;\n\nexport function combineDisplayedStackedData(\n  stackedGraphicalItems: ReadonlyArray<DefinitelyStackedGraphicalItem>,\n  { chartData = [] }: ChartDataState,\n  tooltipAxisSettings: BaseCartesianAxis,\n): DisplayedStackedData {\n  const { allowDuplicatedCategory, dataKey: tooltipDataKey } = tooltipAxisSettings;\n\n  // A map of tooltip data keys to the stacked data points\n  const knownItemsByDataKey = new Map<string | number, DisplayedStackedDataPoint>();\n\n  stackedGraphicalItems.forEach(item => {\n    // If there is no data on the individual item then we use the root chart data\n    const resolvedData = item.data ?? chartData;\n    if (resolvedData == null || resolvedData.length === 0) {\n      // if that doesn't work then we skip this item\n      return;\n    }\n    const stackIdentifier = getStackSeriesIdentifier(item);\n    resolvedData.forEach((entry, index) => {\n      const tooltipValue =\n        tooltipDataKey == null || allowDuplicatedCategory\n          ? index\n          : String(getValueByDataKey(entry, tooltipDataKey, null));\n      const numericValue = getValueByDataKey(entry, item.dataKey, 0);\n      let curr;\n      if (knownItemsByDataKey.has(tooltipValue)) {\n        curr = knownItemsByDataKey.get(tooltipValue)!;\n      } else {\n        curr = {};\n      }\n      Object.assign(curr, { [stackIdentifier]: numericValue });\n      knownItemsByDataKey.set(tooltipValue, curr);\n    });\n  });\n  return Array.from(knownItemsByDataKey.values());\n}\n","import { GraphicalItemSettings } from '../graphicalItemsSlice';\nimport { NormalizedStackId } from '../../util/ChartUtils';\nimport { DataKey } from '../../util/types';\n\n/**\n * Some graphical items allow data stacking. The stacks are optional,\n * so all props here are optional too.\n */\nexport interface MaybeStackedGraphicalItem extends GraphicalItemSettings {\n  stackId: NormalizedStackId | undefined;\n  /**\n   * Bars have a size but Area does not.\n   */\n  barSize: number | string | undefined;\n}\n\n/**\n * Some graphical items allow data stacking.\n * This interface is used to represent the items that are stacked\n * because the user has provided the stackId and dataKey properties.\n */\nexport interface DefinitelyStackedGraphicalItem extends MaybeStackedGraphicalItem {\n  stackId: NormalizedStackId;\n  dataKey: DataKey<any>;\n}\n\nexport function isStacked<T extends GraphicalItemSettings>(\n  graphicalItem: T,\n): graphicalItem is T & DefinitelyStackedGraphicalItem {\n  return 'stackId' in graphicalItem && graphicalItem.stackId != null && graphicalItem.dataKey != null;\n}\n","import { NumberDomain } from '../../util/types';\n\nexport const numberDomainEqualityCheck = (a: NumberDomain | undefined, b: NumberDomain | undefined): boolean => {\n  if (a === b) {\n    return true;\n  }\n  if (a == null || b == null) {\n    return false;\n  }\n  return a[0] === b[0] && a[1] === b[1];\n};\n","/**\n * Checks if two arrays are equal, treating empty arrays as equal regardless of reference.\n * If both arrays are non-empty, it checks for reference equality.\n * @param a\n * @param b\n */\nexport function emptyArraysAreEqualCheck<T>(a: ReadonlyArray<T>, b: ReadonlyArray<T>): boolean {\n  if (Array.isArray(a) && Array.isArray(b) && a.length === 0 && b.length === 0) {\n    // empty arrays are always equal, regardless of reference\n    return true;\n  }\n  return a === b;\n}\n\n/**\n * Checks if two arrays have the same contents in the same order.\n * @param a\n * @param b\n */\nexport function arrayContentsAreEqualCheck<T>(a: ReadonlyArray<T>, b: ReadonlyArray<T>): boolean {\n  if (a.length === b.length) {\n    for (let i = 0; i < a.length; i++) {\n      if (a[i] !== b[i]) {\n        return false;\n      }\n    }\n    return true;\n  }\n  return false;\n}\n","import { RechartsRootState } from '../store';\nimport { selectChartLayout } from '../../context/chartLayoutContext';\n\n/**\n * angle, radius, X, Y, and Z axes all have domain and range and scale and associated settings\n */\nexport type AllAxisTypes = 'xAxis' | 'yAxis' | 'zAxis' | 'radiusAxis' | 'angleAxis';\n\n/**\n * Z axis is never displayed and so it lacks ticks and tick settings.\n */\nexport type RenderableAxisType = 'xAxis' | 'yAxis' | 'angleAxis' | 'radiusAxis';\n\nexport const selectTooltipAxisType = (state: RechartsRootState): RenderableAxisType => {\n  const layout = selectChartLayout(state);\n\n  if (layout === 'horizontal') {\n    return 'xAxis'